{"code": "import json
import os

# Process the first batch of 50 NYSE Arca ETFs to find those > $200 in 2015

# Load results from first batch query
results_file = locals()['var_functions.query_db:98']
if isinstance(results_file, str) and os.path.exists(results_file):
    with open(results_file, 'r') as f:
        batch1_results = json.load(f)
else:
    batch1_results = results_file

# Identify ETFs that exceeded $200
top_etfs = []
valid_etfs = []

for result in batch1_results:
    symbol = result['Symbol']
    max_price = result['max_price']
    days_above = result['days_above_200']

    # Skip NaN results
    if max_price != 'nan' and days_above != 'nan':
        valid_etfs.append({
            'symbol': symbol,
            'max_price': float(max_price),
            'days_above_200': float(days_above)
        })

        if max_price != 'nan' and float(max_price) > 200:
            top_etfs.append({
                'symbol': symbol,
                'max_price': float(max_price),
                'days_above_200': float(days_above)
            })

# Save results for this batch
with open('/tmp/batch1_analysis.json', 'w') as f:
    json.dump({
        'top_etfs': top_etfs,
        'valid_etfs': valid_etfs,
        'nan_count': len(batch1_results) - len(valid_etfs)
    }, f)

print('__RESULT__:')
print(json.dumps({
    'batch_1_total': len(batch1_results),
    'valid_results': len(valid_etfs),
    'etfs_over_200': len(top_etfs),
    'top_performers': top_etfs,
    'sample_valid': valid_etfs[:5]
}))"}
